import { GoogleGenAI, Chat } from "@google/genai";

let chatSession: Chat | null = null;

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.warn("API_KEY is not defined in process.env");
    return null;
  }
  return new GoogleGenAI({ apiKey });
};

export const initializeChat = () => {
  const ai = getAiClient();
  if (!ai) return;

  chatSession = ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: `You are the digital assistant for Danielle Royer's portfolio website. 
      Danielle is a creative developer and designer who loves Neobrutalism, Mondrian art, and functional minimalism.

      Your tone should be:
      - Direct and concise (brutalist).
      - Helpful but slightly robotic or artistic.
      - Knowledgeable about design and code.

      Key info about Danielle:
      - Email: hello@danielleroyer.com
      - Style: Bold, high contrast, structural.
      - Skills: React, TypeScript, UI/UX, Branding.

      If asked about projects, mention she has worked on 'Neon Horizon' and 'Abstract Echo'.
      If asked for contact, provide the email.

      Keep answers short (under 50 words) unless requested otherwise.`,
    },
  });
};

export const sendMessageToGemini = async (message: string): Promise<string> => {
  if (!chatSession) {
    initializeChat();
  }

  if (!chatSession) {
    return "System Error: AI Identity module not found (Missing API Key).";
  }

  try {
    const response = await chatSession.sendMessage({ message });
    return response.text || "System Malfunction: Empty response.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "System Error: Connection severed.";
  }
};

import React from 'react';

interface NeoButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'accent' | 'dark';
  size?: 'sm' | 'md' | 'lg';
}

const NeoButton: React.FC<NeoButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  className = '', 
  ...props 
}) => {

  const baseStyles = "font-bold border-4 border-black transition-all active:translate-x-[4px] active:translate-y-[4px] active:shadow-none uppercase tracking-wider";

  const variants = {
    primary: "bg-mondrian-red text-white shadow-neo hover:bg-red-700",
    secondary: "bg-mondrian-blue text-white shadow-neo hover:bg-blue-800",
    accent: "bg-mondrian-yellow text-black shadow-neo hover:bg-yellow-500",
    dark: "bg-mondrian-black text-white shadow-neo hover:bg-gray-800",
  };

  const sizes = {
    sm: "px-4 py-2 text-sm shadow-neo-sm active:translate-x-[2px] active:translate-y-[2px]",
    md: "px-6 py-3 text-base",
    lg: "px-8 py-4 text-xl shadow-neo-lg",
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

export default NeoButton;

