import React from 'react';

interface NeoButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'accent' | 'dark';
  size?: 'sm' | 'md' | 'lg';
}

const NeoButton: React.FC<NeoButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  className = '', 
  ...props 
}) => {

  const baseStyles = "font-bold border-2 border-black transition-all active:translate-x-[2px] active:translate-y-[2px] active:shadow-none tracking-wide rounded-md";

  const variants = {
    primary: "bg-neo-pastel-pink text-neo-text shadow-neo hover:bg-pink-200",
    secondary: "bg-neo-pastel-blue text-neo-text shadow-neo hover:bg-blue-200",
