            <div className="text-lg font-medium text-gray-700 leading-relaxed border-l-4 border-neo-pink-light pl-6 py-1 space-y-4">
              {project.description.split('\n\n').map((paragraph, idx) => (
                <p key={idx}>{paragraph}</p>
              ))}
